sp_header_footer.client_script:
api.controller = function($scope, $timeout){

var c = this;


	/* ======================
   INITIAL STATE
====================== */

c.notifications = [];
c.unreadCount = 0;

c.cart = [];
c.cartCount = 0;

c.showNotificationPanel = false;
c.showCartPanel = false;

$scope.showHelp = false;
$scope.showMenu = false;

/* ======================
   CART TOGGLE
====================== */

c.toggleCart = function($event){

if($event) $event.stopPropagation();

c.showCartPanel = !c.showCartPanel;

c.showNotificationPanel = false;
$scope.showHelp = false;
$scope.showMenu = false;

if(c.showCartPanel){
c.loadCart();
}

};


/* ======================
   HELP MODAL TOGGLE
====================== */

$scope.toggleHelp = function(){

$scope.showHelp = !$scope.showHelp;

$scope.showMenu = false;

};


/* ======================
   PROFILE MENU TOGGLE
====================== */

$scope.toggleMenu = function(){

$scope.showMenu = !$scope.showMenu;

$scope.showHelp = false;

};


/* ======================
   PROFILE NAVIGATION
====================== */

$scope.openProfile = function(){

window.location.href = "/datamigration?id=dm_profile";

};


/* ======================
   LOGOUT
====================== */

$scope.logout = function(){

window.location.href = "/logout.do";

};


/* ======================
   LOAD CART DATA
====================== */

c.loadCart = function(){

var raw = JSON.parse(
sessionStorage.getItem("migration_cart") || "[]"
);

var grouped = {};

raw.forEach(function(item){

if(!grouped[item.table]){

grouped[item.table] = {

name:item.table,
label:item.label,
records:[]

};

}

grouped[item.table].records.push({

number:item.number || item.sys_id,

short_description:
item.short_description || "",

sys_id:item.sys_id

});

});

c.cart = Object.keys(grouped).map(function(key){

return grouped[key];

});

c.cartCount = raw.length;

};


/* ======================
   LIVE CART UPDATE (SAME TAB)
====================== */

window.addEventListener("cartUpdated", function(){

$scope.$applyAsync(function(){

c.loadCart();

});

});


/* ======================
   CROSS TAB CART UPDATE
====================== */

window.addEventListener("storage", function(){

$scope.$applyAsync(function(){

c.loadCart();

});

});


/* ======================
   INITIAL CART LOAD
====================== */

$timeout(function(){

c.loadCart();

},100);


/* ======================
   OUTSIDE CLICK CLOSE
====================== */

angular.element(document).on("click", function(event){

var insideCartModal =
event.target.closest(".cart-modal");

var insideCartIcon =
event.target.closest(".cart");

var insideNotification =
event.target.closest(".notification-modal");

var insideProfile =
event.target.closest(".profile-wrapper");

var insideHelp =
event.target.closest(".help-modal");

if(!insideCartModal &&
   !insideCartIcon &&
   !insideNotification &&
   !insideProfile &&
   !insideHelp){

$scope.$applyAsync(function(){

c.showCartPanel = false;
c.showNotificationPanel = false;

$scope.showHelp = false;
$scope.showMenu = false;

});

}

});


/* ======================
   LOAD NOTIFICATIONS
====================== */

c.loadNotifications = function(){

c.server.get({

action:"getNotifications"

}).then(function(response){

if(response.data.notifications){

c.notifications = response.data.notifications;

var count = 0;

angular.forEach(c.notifications,function(n){

if(!n.read) count++;

});

c.unreadCount = count;

}

});

};


/* ======================
   TOGGLE NOTIFICATIONS
====================== */

c.toggleNotifications = function(){

c.showNotificationPanel = !c.showNotificationPanel;

c.showCartPanel = false;

$scope.showHelp = false;
$scope.showMenu = false;

};


/* ======================
   MARK SINGLE READ
====================== */

c.markAsRead = function(notification){

notification.read = true;

if(c.unreadCount>0)
c.unreadCount--;

c.server.get({

action:"markNotificationRead",
id:notification.id

});

};


/* ======================
   MARK ALL READ
====================== */

c.markAllAsRead = function(){

angular.forEach(c.notifications,function(n){

n.read = true;

});

c.unreadCount = 0;

c.server.get({

action:"markAllNotificationsRead"

});

};


/* ======================
   NAVIGATE TO CART PAGE
====================== */

c.openCartPage = function(){

var conn = sessionStorage.getItem("currentId");

window.location.href =
"?id=dm_cart&sys_id=" + conn;

};


/* ======================
   AUTO REFRESH NOTIFICATIONS
====================== */

function notificationPolling(){

c.loadNotifications();

$timeout(notificationPolling,15000);

}

notificationPolling();


};

sp_header_footer.css:
*{
	outline-style:none!important;
}

.dm-header{
