transition:.2s ease;

}


.cart-action-btn:hover{

 background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;

}
/* ================= EMPTY CART STATE ================= */
.cart-empty-state{

position:absolute;

top:50%;
left:50%;

transform:translate(-50%, -50%);

display:flex;

flex-direction:column;

align-items:center;

justify-content:center;

text-align:center;

gap:14px;

width:100%;

pointer-events:none;

}


.cart-empty-icon{

width:110px;

height:110px;

border-radius:50%;

background:#eef2f7;

display:flex;

align-items:center;

justify-content:center;

color:#1F8C95;

}


.cart-empty-title{

font-size:22px;

font-weight:600;

color:#111827;

}

.cart-modal:hover{

outline:2px solid #1F8C95;

outline-offset:2px;

box-shadow:

0 35px 90px rgba(0,0,0,.22),

0 0 0 4px rgba(31,140,149,.08);

}
.cart-empty-subtitle{

font-size:14px;

color:#6b7280;

max-width:260px;

line-height:1.5;

}
.cart-scroll-area {

flex:1;

overflow-y:auto;

padding-right:4px;

}

sp_header_footer.script:
(function(){

data.dt="";

var user=gs.getUser();

data.user={

name:user.getDisplayName(),
sys_id:user.getID()

};


/* INITIALS */

var initials="";

var parts=data.user.name.split(" ");

for(var i=0;i<parts.length;i++)
initials+=parts[i].charAt(0);

data.user.initials=initials.substring(0,2).toUpperCase();


/* GET NOTIFICATIONS */

if(input && input.action=="getNotifications"){

data.notifications=[];

var notif=new GlideRecord("x_sysus_data_mig_0_notifications");

notif.addQuery("user",gs.getUserID());

notif.orderByDesc("sys_created_on");

notif.setLimit(20);

notif.query();

while(notif.next()){

data.notifications.push({

id:notif.getUniqueValue(),
title:notif.getValue("title"),
message:notif.getValue("message"),
priority:notif.getValue("priority"),
read:notif.getValue("read")==true,
time:notif.getDisplayValue("sys_created_on")

});

}

return;

}


/* MARK SINGLE */

if(input && input.action=="markNotificationRead"){

var rec=new GlideRecord("x_sysus_data_mig_0_notifications");

if(rec.get(input.id)){

rec.read=true;
rec.update();

}

return;

}


/* MARK ALL */

if(input && input.action=="markAllNotificationsRead"){

var recAll=new GlideRecord("x_sysus_data_mig_0_notifications");

recAll.addQuery("user",gs.getUserID());

recAll.addQuery("read",false);

recAll.query();

while(recAll.next()){

recAll.read=true;
recAll.update();

}

return;

}


/* CONNECTION STATUS 

var chk = new GlideRecord('x_sysus_data_mig_0_connection');
	chk.addQuery('state',true);
	chk.addQuery('sys_created_by',gs.getUserName());
	chk.query();
	if(chk.next()){
		data.dt = chk.getValue('name');
	}

*/
/* DEMO FALLBACK */

data.notifications=[];

var gr=new GlideRecord("sys_journal_field");

gr.addQuery("sys_created_by",user.getName());

gr.orderByDesc("sys_created_on");

gr.setLimit(5);

gr.query();

while(gr.next()){

data.notifications.push({

title:gr.getValue("value").substring(0,60),
time:gr.getDisplayValue("sys_created_on")

});

}

})();
